1	import * as THREE from 'three';
2	import type { Element } from '@bim-ai/core';
3	import { resolveMaterial, type ViewportPaintBundle } from './materials';
4	import { addEdges, categoryColorOr } from './sceneHelpers';
5	import { roofHeightAtPoint } from './roofHeightSampler';
6	
7	function elevationMForLevel(levelId: string, elementsById: Record<string, Element>): number {
8	  const lvl = elementsById[levelId];
9	  if (!lvl || lvl.kind !== 'level') return 0;
10	  return lvl.elevationMm / 1000;
11	}
12	
13	type DormerElem = Extract<Element, { kind: 'dormer' }>;
14	type RoofElem = Extract<Element, { kind: 'roof' }>;
15	type WallElem = Extract<Element, { kind: 'wall' }>;
16	
17	/**
18	 * KRN-14 — compute the dormer footprint (axis-aligned rectangle) in plan
19	 * coordinates (mm), given the host roof's footprint and the dormer's
20	 * positionOnRoof. Convention:
21	 *   - the longer span axis of the host footprint is taken as the ridge axis
22	 *     (matching `makeRoofMassMesh`)
23	 *   - `alongRidgeMm` is a signed offset of the dormer centre along the ridge
24	 *     direction from the footprint centre
25	 *   - `acrossRidgeMm` is a signed offset perpendicular to the ridge from the
26	 *     footprint centre (positive = +plan-X for ridges along plan-Y, or
27	 *     +plan-Y for ridges along plan-X)
28	 */
29	export function dormerFootprintMm(
30	  dormer: DormerElem,
31	  hostRoof: RoofElem,
32	): { minX: number; maxX: number; minY: number; maxY: number; ridgeAlongX: boolean } {
33	  const xs = hostRoof.footprintMm.map((p) => p.xMm);
34	  const ys = hostRoof.footprintMm.map((p) => p.yMm);
35	  const minRx = Math.min(...xs);
36	  const maxRx = Math.max(...xs);
37	  const minRy = Math.min(...ys);
38	  const maxRy = Math.max(...ys);
39	  const cx = (minRx + maxRx) / 2;
40	  const cy = (minRy + maxRy) / 2;
41	  const spanX = maxRx - minRx;
42	  const spanY = maxRy - minRy;
43	  // Match makeRoofMassMesh's heuristic when ridgeAxis is unset: longer plan
44	  // axis becomes the ridge.
45	  const ridgeAlongX =
46	    hostRoof.ridgeAxis === 'x' ? true : hostRoof.ridgeAxis === 'z' ? false : spanX >= spanY;
47	
48	  const dx = ridgeAlongX ? dormer.positionOnRoof.alongRidgeMm : dormer.positionOnRoof.acrossRidgeMm;
49	  const dy = ridgeAlongX ? dormer.positionOnRoof.acrossRidgeMm : dormer.positionOnRoof.alongRidgeMm;
50	  const centreX = cx + dx;
51	  const centreY = cy + dy;
52	
53	  const halfWidth = dormer.widthMm / 2;
54	  const halfDepth = dormer.depthMm / 2;
55	
56	  // Width runs along the ridge; depth runs across.
57	  if (ridgeAlongX) {
58	    return {
59	      minX: centreX - halfWidth,
60	      maxX: centreX + halfWidth,
61	      minY: centreY - halfDepth,
62	      maxY: centreY + halfDepth,
63	      ridgeAlongX,
64	    };
65	  }
66	  return {
67	    minX: centreX - halfDepth,
68	    maxX: centreX + halfDepth,
69	    minY: centreY - halfWidth,
70	    maxY: centreY + halfWidth,
71	    ridgeAlongX,
72	  };
73	}
74	
75	/**
76	 * Build a dormer Group: cheek walls + back wall + flat dormer roof. The
77	 * "front" face of the dormer is left open (this is where hosted glass doors
78	 * go; in the demo seed they sit on the upper-volume east wall, which serves
79	 * as the dormer's interior back wall, with the open side pointing toward
80	 * the deck).
81	 */
82	export function makeDormerMesh(
83	  dormer: DormerElem,
84	  elementsById: Record<string, Element>,
85	  paint: ViewportPaintBundle | null,
86	): THREE.Group {
87	  const group = new THREE.Group();
88	  group.userData.bimPickId = dormer.id;
89	
90	  const hostRoof = elementsById[dormer.hostRoofId];
91	  if (!hostRoof || hostRoof.kind !== 'roof') return group;
92	
93	  const fp = dormerFootprintMm(dormer, hostRoof);
94	
95	  // Reference elevation: top of upper-floor walls (eave plate) at host roof's
96	  // reference level. Use the same heuristic as makeRoofMassMesh.
97	  const refElev = elevationMForLevel(hostRoof.referenceLevelId, elementsById);
98	  const wallsAtRef = Object.values(elementsById).filter(
99	    (e): e is WallElem =>
100	      e.kind === 'wall' && (e as WallElem).levelId === hostRoof.referenceLevelId,
101	  );
102	  const centreXmm = (fp.minX + fp.maxX) / 2;
103	  const centreYmm = (fp.minY + fp.maxY) / 2;
104	  const wallTopM =
105	    wallsAtRef.length > 0 ? Math.max(...wallsAtRef.map((w) => (w.heightMm ?? 0) / 1000)) : 0;
106	  const roofPlaneY = roofHeightAtPoint(hostRoof, elementsById, centreXmm, centreYmm);
107	  const baseY = Math.max(refElev + wallTopM, roofPlaneY - 0.05);
108	  const wallHeightM = THREE.MathUtils.clamp(dormer.wallHeightMm / 1000, 0.5, 8);
109	  const topY = baseY + wallHeightM;
110	
111	  // World coords: plan-X → world-X, plan-Y → world-Z (no negation,
112	  // matching the wall + roof builders elsewhere in viewport/meshBuilders.ts).
113	  // The earlier negated convention placed dormer geometry ~plan-depth metres
114	  // away from the host building in world Z, rendering it invisible.
115	  const xMin = fp.minX / 1000;
116	  const xMax = fp.maxX / 1000;
117	  const zMin = fp.minY / 1000;
118	  const zMax = fp.maxY / 1000;
119	  const widthM = xMax - xMin;
120	  const depthM = zMax - zMin;
121	  const cheekThickM = 0.18;
122	  const roofThickM = 0.12;
123	  const openTowardPositiveAcross = (dormer.positionOnRoof.acrossRidgeMm ?? 0) >= 0;
124	
125	  const wallSpec = resolveMaterial(dormer.wallMaterialKey ?? null);
126	  const wallColor = wallSpec?.baseColor ?? '#f4f4f0';
127	  const wallIsRender = wallSpec?.category === 'render' || wallSpec?.category === 'cladding';
128	  const wallMat = new THREE.MeshStandardMaterial({
129	    color: new THREE.Color(wallColor),
130	    roughness: wallSpec?.roughness ?? 0.92,
131	    metalness: wallSpec?.metalness ?? 0,
132	    envMapIntensity: wallIsRender ? 0.15 : 1.0,
133	  });
134	
135	  const roofSpec = resolveMaterial(dormer.roofMaterialKey ?? null);
136	  const roofColor = roofSpec?.baseColor ?? wallColor;
137	  const roofMat = new THREE.MeshStandardMaterial({
138	    color: new THREE.Color(roofColor),
139	    roughness: roofSpec?.roughness ?? 0.85,
140	    metalness: roofSpec?.metalness ?? 0,
141	    envMapIntensity: roofSpec?.category === 'metal_roof' ? 0.4 : 0.15,
142	  });
143	  void categoryColorOr;
144	
145	  // Two cheek walls running along the depth direction (across ridge for
146	  // ridgeAlongX=false). For our target house ridge is along plan-Y, so the
147	  // dormer width axis = plan-Y = world-Z, depth axis = plan-X = world-X.
148	  // Cheek walls are perpendicular to the ridge i.e. in the X-Y world plane.
149	  if (fp.ridgeAlongX) {
150	    // Cheeks are walls of constant X (one at xMin, one at xMax), running
151	    // along world-Z for the dormer depth.
152	    for (const xWorld of [xMin + cheekThickM / 2, xMax - cheekThickM / 2]) {
153	      const cheek = new THREE.Mesh(
154	        new THREE.BoxGeometry(cheekThickM, wallHeightM, depthM),
155	        wallMat,
156	      );
157	      cheek.position.set(xWorld, baseY + wallHeightM / 2, (zMin + zMax) / 2);
158	      addEdges(cheek);
159	      group.add(cheek);
160	    }
161	    // Back wall faces the ridge; the open glazed face points down the roof
162	    // slope toward the eave side where the dormer was placed.
163	    const backWallZ = openTowardPositiveAcross ? zMin + cheekThickM / 2 : zMax - cheekThickM / 2;
164	    const backWall = new THREE.Mesh(
165	      new THREE.BoxGeometry(widthM, wallHeightM, cheekThickM),
166	      wallMat,
167	    );
168	    backWall.position.set((xMin + xMax) / 2, baseY + wallHeightM / 2, backWallZ);
169	    addEdges(backWall);
170	    group.add(backWall);
171	    addDormerFaceWindow(group, {
172	      ridgeAlongX: true,
173	      openTowardPositiveAcross,
174	      xMin,
175	      xMax,
176	      zMin,
177	      zMax,
178	      baseY,
179	      wallHeightM,
180	      cheekThickM,
181	    });
182	  } else {
183	    // Ridge along plan-Y → ridge along world-Z. Cheek walls are at zMin,zMax
184	    // running along world-X.
185	    for (const zWorld of [zMin + cheekThickM / 2, zMax - cheekThickM / 2]) {
186	      const cheek = new THREE.Mesh(
187	        new THREE.BoxGeometry(widthM, wallHeightM, cheekThickM),
188	        wallMat,
189	      );
190	      cheek.position.set((xMin + xMax) / 2, baseY + wallHeightM / 2, zWorld);
191	      addEdges(cheek);
192	      group.add(cheek);
193	    }
194	    // Back wall faces the ridge; the open glazed face points down the roof
195	    // slope toward the eave side where the dormer was placed.
196	    const backWallX = openTowardPositiveAcross ? xMin + cheekThickM / 2 : xMax - cheekThickM / 2;
197	    const backWall = new THREE.Mesh(
198	      new THREE.BoxGeometry(cheekThickM, wallHeightM, depthM),
199	      wallMat,
200	    );
201	    backWall.position.set(backWallX, baseY + wallHeightM / 2, (zMin + zMax) / 2);
202	    addEdges(backWall);
203	    group.add(backWall);
204	    addDormerFaceWindow(group, {
205	      ridgeAlongX: false,
206	      openTowardPositiveAcross,
207	      xMin,
208	      xMax,
209	      zMin,
210	      zMax,
211	      baseY,
212	      wallHeightM,
213	      cheekThickM,
214	    });
215	  }
216	
217	  const roofKind = dormer.dormerRoofKind ?? 'flat';
218	  const ridgeHeightM =
219	    dormer.ridgeHeightMm != null ? Math.max(0.1, dormer.ridgeHeightMm / 1000) : 1.2;
220	  const eaveCenterX = (xMin + xMax) / 2;
221	  const eaveCenterZ = (zMin + zMax) / 2;
222	
223	  if (roofKind === 'gable') {
224	    const roof = buildGableDormerRoof(
225	      widthM,
226	      depthM,
227	      roofThickM,
228	      ridgeHeightM,
229	      fp.ridgeAlongX,
230	      roofMat,
231	    );
232	    roof.position.set(eaveCenterX, topY, eaveCenterZ);
233	    addEdges(roof);
234	    group.add(roof);
235	  } else if (roofKind === 'hipped') {
236	    const roof = buildHippedDormerRoof(
237	      widthM,
238	      depthM,
239	      roofThickM,
240	      ridgeHeightM,
241	      fp.ridgeAlongX,
242	      roofMat,
243	    );
244	    roof.position.set(eaveCenterX, topY, eaveCenterZ);
245	    addEdges(roof);
246	    group.add(roof);
247	  } else {
248	    const roofSlab = new THREE.Mesh(new THREE.BoxGeometry(widthM, roofThickM, depthM), roofMat);
249	    roofSlab.position.set(eaveCenterX, topY + roofThickM / 2, eaveCenterZ);
250	    addEdges(roofSlab);
251	    group.add(roofSlab);
252	  }
253	
254	  void paint;
255	  return group;
256	}
257	
258	function addDormerFaceWindow(
259	  group: THREE.Group,
260	  spec: {
261	    ridgeAlongX: boolean;
262	    openTowardPositiveAcross: boolean;
263	    xMin: number;
264	    xMax: number;
265	    zMin: number;
266	    zMax: number;
267	    baseY: number;
268	    wallHeightM: number;
269	    cheekThickM: number;
270	  },
271	): void {
272	  const glassSpec = resolveMaterial('glass_clear');
273	  const frameSpec = resolveMaterial('aluminium_dark_grey');
274	  const glassMat = new THREE.MeshStandardMaterial({
275	    color: new THREE.Color(glassSpec?.baseColor ?? '#b8d6e6'),
276	    roughness: glassSpec?.roughness ?? 0.05,
277	    metalness: glassSpec?.metalness ?? 0,
278	    transparent: true,
279	    opacity: 0.62,
280	    envMapIntensity: 0.9,
281	  });
282	  const frameMat = new THREE.MeshStandardMaterial({
283	    color: new THREE.Color(frameSpec?.baseColor ?? '#343638'),
284	    roughness: frameSpec?.roughness ?? 0.35,
285	    metalness: frameSpec?.metalness ?? 0.4,
286	  });
287	
288	  const widthM = spec.xMax - spec.xMin;
289	  const depthM = spec.zMax - spec.zMin;
290	  const glassHeight = Math.max(0.65, spec.wallHeightM * 0.52);
291	  const y = spec.baseY + spec.wallHeightM * 0.48;
292	  const frame = 0.045;
293	  const thin = 0.04;
294	
295	  if (spec.ridgeAlongX) {
296	    const glassWidth = Math.max(0.7, widthM * 0.72);
297	    const z = spec.openTowardPositiveAcross
298	      ? spec.zMax - spec.cheekThickM / 2
299	      : spec.zMin + spec.cheekThickM / 2;
300	    const glass = new THREE.Mesh(new THREE.BoxGeometry(glassWidth, glassHeight, thin), glassMat);
301	    glass.position.set((spec.xMin + spec.xMax) / 2, y, z);
302	    group.add(glass);
303	    for (const x of [
304	      (spec.xMin + spec.xMax) / 2 - glassWidth / 2,
305	      (spec.xMin + spec.xMax) / 2,
306	      (spec.xMin + spec.xMax) / 2 + glassWidth / 2,
307	    ]) {
308	      const mullion = new THREE.Mesh(
309	        new THREE.BoxGeometry(frame, glassHeight + frame, thin * 1.4),
310	        frameMat,
311	      );
312	      mullion.position.set(x, y, z);
313	      group.add(mullion);
314	    }
315	    for (const yy of [y - glassHeight / 2, y + glassHeight / 2]) {
316	      const rail = new THREE.Mesh(
317	        new THREE.BoxGeometry(glassWidth + frame, frame, thin * 1.4),
318	        frameMat,
319	      );
320	      rail.position.set((spec.xMin + spec.xMax) / 2, yy, z);
321	      group.add(rail);
322	    }
323	    return;
324	  }
325	
326	  const glassWidth = Math.max(0.7, depthM * 0.72);
327	  const x = spec.openTowardPositiveAcross
328	    ? spec.xMax - spec.cheekThickM / 2
329	    : spec.xMin + spec.cheekThickM / 2;
330	  const glass = new THREE.Mesh(new THREE.BoxGeometry(thin, glassHeight, glassWidth), glassMat);
331	  glass.position.set(x, y, (spec.zMin + spec.zMax) / 2);
332	  group.add(glass);
333	  for (const z of [
334	    (spec.zMin + spec.zMax) / 2 - glassWidth / 2,
335	    (spec.zMin + spec.zMax) / 2,
336	    (spec.zMin + spec.zMax) / 2 + glassWidth / 2,
337	  ]) {
338	    const mullion = new THREE.Mesh(
339	      new THREE.BoxGeometry(thin * 1.4, glassHeight + frame, frame),
340	      frameMat,
341	    );
342	    mullion.position.set(x, y, z);
343	    group.add(mullion);
344	  }
345	  for (const yy of [y - glassHeight / 2, y + glassHeight / 2]) {
346	    const rail = new THREE.Mesh(
347	      new THREE.BoxGeometry(thin * 1.4, frame, glassWidth + frame),
348	      frameMat,
349	    );
350	    rail.position.set(x, yy, (spec.zMin + spec.zMax) / 2);
351	    group.add(rail);
352	  }
353	}
354	
355	/** KRN-14 — gable roof for a dormer. */
356	export function buildGableDormerRoof(
357	  widthM: number,
358	  depthM: number,
359	  roofThickM: number,
360	  ridgeHeightM: number,
361	  ridgeAlongX: boolean,
362	  material: THREE.Material,
363	): THREE.Mesh {
364	  const longAlongWorldX = ridgeAlongX ? widthM >= depthM : depthM >= widthM;
365	  const hxWorld = ridgeAlongX ? widthM / 2 : depthM / 2;
366	  const hzWorld = ridgeAlongX ? depthM / 2 : widthM / 2;
367	  const eaveY = roofThickM;
368	  const ridgeY = eaveY + ridgeHeightM;
369	  const positions: number[] = [];
370	  const indices: number[] = [];
371	  if (longAlongWorldX) {
372	    positions.push(-hxWorld, eaveY, -hzWorld);
373	    positions.push(hxWorld, eaveY, -hzWorld);
374	    positions.push(hxWorld, eaveY, hzWorld);
375	    positions.push(-hxWorld, eaveY, hzWorld);
376	    positions.push(-hxWorld, ridgeY, 0);
377	    positions.push(hxWorld, ridgeY, 0);
378	    indices.push(0, 1, 5, 0, 5, 4);
379	    indices.push(2, 3, 4, 2, 4, 5);
380	    indices.push(0, 4, 3);
381	    indices.push(1, 2, 5);
382	  } else {
383	    positions.push(-hxWorld, eaveY, -hzWorld);
384	    positions.push(hxWorld, eaveY, -hzWorld);
385	    positions.push(hxWorld, eaveY, hzWorld);
386	    positions.push(-hxWorld, eaveY, hzWorld);
387	    positions.push(0, ridgeY, -hzWorld);
388	    positions.push(0, ridgeY, hzWorld);
389	    indices.push(1, 2, 5, 1, 5, 4);
390	    indices.push(3, 0, 4, 3, 4, 5);
391	    indices.push(0, 1, 4);
392	    indices.push(2, 3, 5);
393	  }
394	  const geom = new THREE.BufferGeometry();
395	  geom.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
396	  geom.setIndex(indices);
397	  geom.computeVertexNormals();
398	  return new THREE.Mesh(geom, material);
399	}
400	
401	/** KRN-14 — hipped roof for a dormer (ridge shorter than the eave). */
402	export function buildHippedDormerRoof(
403	  widthM: number,
404	  depthM: number,
405	  roofThickM: number,
406	  ridgeHeightM: number,
407	  ridgeAlongX: boolean,
408	  material: THREE.Material,
409	): THREE.Mesh {
410	  const longAlongWorldX = ridgeAlongX ? widthM >= depthM : depthM >= widthM;
411	  const hxWorld = ridgeAlongX ? widthM / 2 : depthM / 2;
412	  const hzWorld = ridgeAlongX ? depthM / 2 : widthM / 2;
413	  const eaveY = roofThickM;
414	  const ridgeY = eaveY + ridgeHeightM;
415	  const longHalf = longAlongWorldX ? hxWorld : hzWorld;
416	  const ridgeHalf = Math.max(0.05, longHalf * 0.5);
417	  const positions: number[] = [];
418	  const indices: number[] = [];
419	  if (longAlongWorldX) {
420	    positions.push(-hxWorld, eaveY, -hzWorld);
421	    positions.push(hxWorld, eaveY, -hzWorld);
422	    positions.push(hxWorld, eaveY, hzWorld);
423	    positions.push(-hxWorld, eaveY, hzWorld);
424	    positions.push(-ridgeHalf, ridgeY, 0);
425	    positions.push(ridgeHalf, ridgeY, 0);
426	    indices.push(0, 1, 5, 0, 5, 4);
427	    indices.push(2, 3, 4, 2, 4, 5);
428	    indices.push(3, 0, 4);
429	    indices.push(1, 2, 5);
430	  } else {
431	    positions.push(-hxWorld, eaveY, -hzWorld);
432	    positions.push(hxWorld, eaveY, -hzWorld);
433	    positions.push(hxWorld, eaveY, hzWorld);
434	    positions.push(-hxWorld, eaveY, hzWorld);
435	    positions.push(0, ridgeY, -ridgeHalf);
436	    positions.push(0, ridgeY, ridgeHalf);
437	    indices.push(1, 2, 5, 1, 5, 4);
438	    indices.push(3, 0, 4, 3, 4, 5);
439	    indices.push(0, 1, 4);
440	    indices.push(2, 3, 5);
441	  }
442	  const geom = new THREE.BufferGeometry();
443	  geom.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
444	  geom.setIndex(indices);
445	  geom.computeVertexNormals();
446	  return new THREE.Mesh(geom, material);
447	}
